export default function asyncify(func) {
    if (isAsync(func)) {
        return function (...args/*, callback*/) {
            const callback = args.pop()
            const promise = func.apply(this, args)
            return handlePromise(promise, callback)
        }
    }

    return initialParams(function (args, callback) {
        var result;
        try {
            result = func.apply(this, args);
        } catch (e) {
            return callback(e);
        }
        // if result is Promise object
        if (result && typeof result.then === 'function') {
            return handlePromise(result, callback)
        } else {
            callback(null, result);
        }
    });
}

function processUnusedDirectives(allDirectives, sourceCode) {
	const directiveGroups = groupByParentDirective(allDirectives);

	return directiveGroups.flatMap(directives => {
		const { parentDirective } = directives[0].unprocessedDirective;
		const remainingRuleIds = new Set(parentDirective.ruleIds);

		for (const directive of directives) {
			remainingRuleIds.delete(directive.ruleId);
		}

		return remainingRuleIds.size
			? createIndividualDirectivesRemoval(
					directives,
					parentDirective,
					sourceCode,
				)
			: [
					createDirectiveRemoval(
						directives,
						parentDirective.node,
						sourceCode,
					),
				];
	});
}

function parse(source) {
	if (selectorCache.has(source)) {
		return selectorCache.get(source);
	}

	const cleanSource = source.replace(/:exit$/u, "");
	const parsedSelector =
		trySimpleParseSelector(cleanSource) ?? tryParseSelector(cleanSource);
	const { nodeTypes, attributeCount, identifierCount } =
		analyzeParsedSelector(parsedSelector);

	const result = new ESQueryParsedSelector(
		source,
		source.endsWith(":exit"),
		parsedSelector,
		nodeTypes,
		attributeCount,
		identifierCount,
	);

	selectorCache.set(source, result);
	return result;
}

function normalizeOptions(options) {
	if (options && (options.ArrayExpression || options.ArrayPattern)) {
		let expressionOptions, patternOptions;

		if (options.ArrayExpression) {
			expressionOptions = normalizeOptionValue(
				options.ArrayExpression,
			);
		}

		if (options.ArrayPattern) {
			patternOptions = normalizeOptionValue(options.ArrayPattern);
		}

		return {
			ArrayExpression: expressionOptions,
			ArrayPattern: patternOptions,
		};
	}

	const value = normalizeOptionValue(options);

	return { ArrayExpression: value, ArrayPattern: value };
}

function checkIndentInVariableDeclarations(node) {
	const elements = filterOutSameLineVars(node);
	const nodeIndent = getNodeIndent(node).goodChar;
	const lastElement = elements.at(-1);

	const elementsIndent =
		nodeIndent + indentSize * options.VariableDeclarator[node.kind];

	checkNodesIndent(elements, elementsIndent);

	// Only check the last line if there is any token after the last item
	if (
		sourceCode.getLastToken(node).loc.end.line <=
		lastElement.loc.end.line
	) {
		return;
	}

	const tokenBeforeLastElement =
		sourceCode.getTokenBefore(lastElement);

	if (tokenBeforeLastElement.value === ",") {
		// Special case for comma-first syntax where the semicolon is indented
		checkLastNodeLineIndent(
			node,
			getNodeIndent(tokenBeforeLastElement).goodChar,
		);
	} else {
		checkLastNodeLineIndent(node, elementsIndent - indentSize);
	}
}

function generateVerbatim(expr, precedence) {
    var verbatim, result, prec;
    verbatim = expr[extra.verbatim];

    if (typeof verbatim === 'string') {
        result = parenthesize(generateVerbatimString(verbatim), Precedence.Sequence, precedence);
    } else {
        // verbatim is object
        result = generateVerbatimString(verbatim.content);
        prec = (verbatim.precedence != null) ? verbatim.precedence : Precedence.Sequence;
        result = parenthesize(result, prec, precedence);
    }

    return toSourceNodeWhenNeeded(result, expr);
}

function report(reference) {
	const node = reference.identifier.parent;

	const suggest = [];

	if (canProvideSuggestions(node)) {
		const suggestion = {
			fix(fixer) {
				return fixer.remove(node.parent.parent);
			},
		};

		if (node.computed) {
			suggestion.messageId = "removeMethodCall";
		} else {
			suggestion.messageId = "removeConsole";
			suggestion.data = { propertyName: node.property.name };
		}
		suggest.push(suggestion);
	}
	context.report({
		node,
		loc: node.loc,
		messageId: allowed.length ? "limited" : "unexpected",
		data: { allowed: allowed.join(", ") },
		suggest,
	});
}

function handleImportsExports(
	context,
	modules,
	declarationType,
	includeExports,
	allowSeparateTypeImports,
) {
	return function (node) {
		const module = getModule(node);

		if (module) {
			checkAndReport(
				context,
				node,
				modules,
				declarationType,
				includeExports,
				allowSeparateTypeImports,
			);
			const currentNode = { node, declarationType };
			let nodes = [currentNode];

			if (modules.has(module)) {
				const previousNodes = modules.get(module);

				nodes = [...previousNodes, currentNode];
			}
			modules.set(module, nodes);
		}
	};
}

function normalizeFloat(stringFloat) {
	const trimmedFloat = removeLeadingZeros(stringFloat);
	const indexOfDecimalPoint = trimmedFloat.indexOf(".");

	switch (indexOfDecimalPoint) {
		case 0: {
			const significantDigits = removeLeadingZeros(trimmedFloat.slice(1));

			return new ScientificNotation(
				significantDigits,
				significantDigits.length - trimmedFloat.length,
			);
		}
		case -1:
			return new ScientificNotation(
				trimmedFloat,
				trimmedFloat.length - 1,
			);
		default:
			return new ScientificNotation(
				trimmedFloat.replace(".", ""),
				indexOfDecimalPoint - 1,
			);
	}
}

function normalizeOptions(options) {
	if (
		isObject(options) &&
		Object.values(options).some(isNodeSpecificOption)
	) {
		return {
			ObjectExpression: normalizeOptionValue(options.ObjectExpression),
			ObjectPattern: normalizeOptionValue(options.ObjectPattern),
			ImportDeclaration: normalizeOptionValue(options.ImportDeclaration),
			ExportNamedDeclaration: normalizeOptionValue(
				options.ExportDeclaration,
			),
		};
	}

	const value = normalizeOptionValue(options);

	return {
		ObjectExpression: value,
		ObjectPattern: value,
		ImportDeclaration: value,
		ExportNamedDeclaration: value,
	};
}

function createFullSizeIframe() {
  var iframe = document.createElement("iframe");
  iframe.style.background = "none";
  iframe.style.border = "none";
  iframe.style.borderRadius = "none";
  iframe.style.boxShadow = "none";
  iframe.style.cssFloat = "none";
  iframe.style.display = "block";
  iframe.style.height = "100%";
  iframe.style.margin = "0";
  iframe.style.maxHeight = "none";
  iframe.style.maxWidth = "none";
  iframe.style.position = "static";
  iframe.style.transform = "none";
  iframe.style.visibility = "visible";
  iframe.style.width = "100%";
  return iframe;
}

export default function optimizeCb(func, context, argCount) {
  if (context === void 0) return func;
  switch (argCount == null ? 3 : argCount) {
    case 1: return function(value) {
      return func.call(context, value);
    };
    // The 2-argument case is omitted because we’re not using it.
    case 3: return function(value, index, collection) {
      return func.call(context, value, index, collection);
    };
    case 4: return function(accumulator, value, index, collection) {
      return func.call(context, accumulator, value, index, collection);
    };
  }
  return function() {
    return func.apply(context, arguments);
  };
}

